<template><div><el-card><div class="toolbar"><el-input v-model="query.adjustmentNo" placeholder="调整单号" clearable style="width:180px"/><el-select v-model="query.warehouseId" placeholder="仓库" clearable style="width:180px"><el-option v-for="w in warehouses" :key="w.value" :label="w.label" :value="w.value"/></el-select><el-select v-model="query.adjustmentType" placeholder="调整类型" clearable style="width:140px"><el-option label="库存增加" value="INCREASE"/><el-option label="报损减少" value="DECREASE"/></el-select><el-select v-model="query.status" placeholder="状态" clearable style="width:120px"><el-option label="草稿" value="DRAFT"/><el-option label="已完成" value="COMPLETED"/><el-option label="已取消" value="CANCELLED"/></el-select><el-button type="primary" @click="fetchData">查询</el-button><el-button @click="reset">重置</el-button><el-button type="success" @click="router.push('/inventory/adjustments/new?type=DECREASE')">新增报损</el-button><el-button @click="router.push('/inventory/adjustments/new?type=INCREASE')">新增库存增加</el-button></div></el-card><el-card class="table-card"><el-table :data="tableData" v-loading="loading" border stripe><el-table-column prop="adjustmentNo" label="调整单号" width="180"/><el-table-column prop="adjustmentDate" label="业务日期" width="120"/><el-table-column prop="warehouseName" label="仓库" min-width="150"/><el-table-column label="调整类型" width="110"><template #default="{row}"><el-tag :type="row.adjustmentType==='DECREASE'?'danger':'success'">{{typeLabel(row.adjustmentType)}}</el-tag></template></el-table-column><el-table-column prop="totalQuantity" label="总数量" width="100" align="right"/><el-table-column prop="totalAmount" label="成本金额" width="120" align="right"/><el-table-column prop="reason" label="调整原因" min-width="180" show-overflow-tooltip/><el-table-column label="状态" width="100"><template #default="{row}"><el-tag :type="statusType(row.status)" size="small">{{statusLabel(row.status)}}</el-tag></template></el-table-column><el-table-column label="操作" width="250" fixed="right"><template #default="{row}"><el-button size="small" @click="router.push(`/inventory/adjustments/${row.id}`)">查看</el-button><el-button v-if="row.status==='DRAFT'" size="small" type="success" @click="approve(row)">审核入账</el-button><el-button v-if="row.status==='DRAFT'" size="small" type="danger" @click="cancel(row)">取消</el-button><el-button v-if="['DRAFT','CANCELLED'].includes(row.status)" size="small" type="danger" plain @click="remove(row)">删除</el-button></template></el-table-column></el-table><el-pagination class="pagination" background layout="total,prev,pager,next" :total="total" v-model:current-page="query.page" v-model:page-size="query.size" @change="fetchData"/></el-card></div></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{useRouter}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{approveInventoryAdjustment,cancelInventoryAdjustment,deleteInventoryAdjustment,getInventoryAdjustments}from'@/api/inventory';import{getWarehouseOptions}from'@/api/masterdata';const router=useRouter(),loading=ref(false),tableData=ref<any[]>([]),total=ref(0),warehouses=ref<any[]>([]),query=reactive({page:1,size:10,adjustmentNo:'',warehouseId:'',adjustmentType:'',status:''});onMounted(async()=>{warehouses.value=(await getWarehouseOptions()).data||[];fetchData()});function typeLabel(v:string){return v==='DECREASE'?'报损减少':'库存增加'}function statusLabel(v:string){return({DRAFT:'草稿',COMPLETED:'已完成',CANCELLED:'已取消'}as any)[v]||v}function statusType(v:string){return({DRAFT:'info',COMPLETED:'success',CANCELLED:'danger'}as any)[v]||''}async function fetchData(){loading.value=true;try{const r=await getInventoryAdjustments(query);tableData.value=r.data.records||[];total.value=r.data.total||0}finally{loading.value=false}}function reset(){Object.assign(query,{page:1,adjustmentNo:'',warehouseId:'',adjustmentType:'',status:''});fetchData()}async function approve(row:any){await ElMessageBox.confirm(`审核后将直接${row.adjustmentType==='DECREASE'?'减少':'增加'}库存，是否继续？`,'审核入账',{type:'warning'});await approveInventoryAdjustment(row.id);ElMessage.success('库存调整已入账');fetchData()}async function cancel(row:any){await ElMessageBox.confirm('确定取消该库存调整单吗？','取消调整',{type:'warning'});await cancelInventoryAdjustment(row.id);ElMessage.success('调整单已取消');fetchData()}async function remove(row:any){await ElMessageBox.confirm('删除后无法恢复，是否继续？','删除调整单',{type:'warning'});await deleteInventoryAdjustment(row.id);ElMessage.success('调整单已删除');fetchData()}</script>
<style scoped>.toolbar{display:flex;gap:10px;flex-wrap:wrap}.table-card{margin-top:12px}.pagination{margin-top:12px;justify-content:flex-end}</style>
